// src/pages/PracticePage.js
import React, { useState } from "react";
import { useRecorder } from "../utils/useRecorder";
import "./PracticePage.css";

const API_URL = process.env.REACT_APP_API_URL || "http://localhost:5000";

// ── Shared Sidebar (mirrors DashboardPage sidebar) ─────────────────────────
function Sidebar({ navigate, onLogout, user }) {
  const displayName = user?.displayName || user?.email?.split("@")[0] || "there";
  const initials = displayName.slice(0, 2).toUpperCase();

  return (
    <aside className="pp-sidebar">
      <div className="pp-sidebar-logo" onClick={() => navigate("landing")}>
        <div className="pp-logo-icon">
          <svg viewBox="0 0 40 40" fill="none" width="22" height="22">
            <defs>
              <linearGradient id="ppg1" x1="0%" y1="0%" x2="100%" y2="100%">
                <stop offset="0%" stopColor="#a99dff"/>
                <stop offset="100%" stopColor="#7c6fcd"/>
              </linearGradient>
            </defs>
            <path d="M28 10C25.3 7.3 21.8 5.5 18 5.5C10.5 5.5 4.5 11.5 4.5 19C4.5 26.5 10.5 32.5 18 32.5C21.8 32.5 25.3 30.7 28 28"
              stroke="url(#ppg1)" strokeWidth="4" strokeLinecap="round"/>
            <path d="M32 9 L33.2 12 L36 13 L33.2 14 L32 17 L30.8 14 L28 13 L30.8 12 Z" fill="url(#ppg1)"/>
          </svg>
        </div>
        <div className="pp-logo-words">
          <span className="pp-logo-text">CLARIO</span>
          <span className="pp-logo-sub">AI SPEECH COACH</span>
        </div>
      </div>

      <nav className="pp-sidenav">
        <button className="pp-nav-item" onClick={() => navigate("dashboard")}>
          <svg width="18" height="18" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth="2">
            <path d="M3 9.5L12 3l9 6.5V20a1 1 0 01-1 1H4a1 1 0 01-1-1V9.5z"/>
            <path d="M9 21V12h6v9"/>
          </svg>
          <span>Home</span>
        </button>

        <button className="pp-nav-item active">
          <svg width="18" height="18" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth="2">
            <path d="M12 1a3 3 0 013 3v8a3 3 0 01-6 0V4a3 3 0 013-3z"/>
            <path d="M19 10a7 7 0 01-14 0M12 19v4M8 23h8"/>
          </svg>
          <span>Practice</span>
        </button>

        <button className="pp-nav-item">
          <svg width="18" height="18" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth="2">
            <rect x="3" y="3" width="7" height="7" rx="1"/>
            <rect x="14" y="3" width="7" height="7" rx="1"/>
            <rect x="3" y="14" width="7" height="7" rx="1"/>
            <rect x="14" y="14" width="7" height="7" rx="1"/>
          </svg>
          <span>Scenarios</span>
        </button>

        <button className="pp-nav-item" onClick={() => navigate("dashboard")}>
          <svg width="18" height="18" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth="2">
            <polyline points="22 12 18 12 15 21 9 3 6 12 2 12"/>
          </svg>
          <span>Progress</span>
        </button>

        <div className="pp-nav-divider" />

        <button className="pp-nav-item">
          <svg width="18" height="18" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth="2">
            <circle cx="12" cy="12" r="3"/>
            <path d="M19.07 4.93a10 10 0 010 14.14M4.93 4.93a10 10 0 000 14.14"/>
          </svg>
          <span>Settings</span>
        </button>

        <button className="pp-nav-item" onClick={onLogout}>
          <svg width="18" height="18" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth="2">
            <path d="M17 16l4-4-4-4M21 12H9M13 4H5a2 2 0 00-2 2v12a2 2 0 002 2h8"/>
          </svg>
          <span>Log out</span>
        </button>
      </nav>

      <div className="pp-premium-box">
        <div className="pp-premium-crown">👑</div>
        <p className="pp-premium-title">Go Premium</p>
        <p className="pp-premium-desc">Unlock advanced insights, personalized tips, and unlimited practice.</p>
        <button className="pp-premium-btn">Upgrade Now</button>
      </div>

      <div className="pp-sidebar-wave">
        <svg viewBox="0 0 220 80" preserveAspectRatio="none">
          <path d="M0 40 Q55 0 110 40 Q165 80 220 40 L220 80 L0 80 Z" fill="rgba(124,108,252,0.12)"/>
        </svg>
      </div>
    </aside>
  );
}

// ── Shared Topbar ──────────────────────────────────────────────────────────
function Topbar({ user }) {
  const displayName = user?.displayName || user?.email?.split("@")[0] || "User";
  const initials = displayName.slice(0, 2).toUpperCase();
  return (
    <header className="pp-topbar">
      <div />
      <div className="pp-topbar-right">
        <button className="pp-notif-btn" aria-label="Notifications">
          <svg width="20" height="20" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth="2">
            <path d="M18 8A6 6 0 006 8c0 7-3 9-3 9h18s-3-2-3-9M13.73 21a2 2 0 01-3.46 0"/>
          </svg>
          <span className="pp-notif-dot" />
        </button>
        <div className="pp-user-pill">
          <div className="pp-user-avatar">{initials}</div>
          <div className="pp-user-info">
            <span className="pp-user-name">{displayName}</span>
            <span className="pp-user-role">Student</span>
          </div>
          <svg width="14" height="14" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth="2" style={{color:"#9090b0"}}>
            <polyline points="6 9 12 15 18 9"/>
          </svg>
        </div>
      </div>
    </header>
  );
}

// ── 3D SVG Illustrations (matching PDF 4 style) ────────────────────────────

// Graduation cap on books
function ThesisIllustration() {
  return (
    <svg viewBox="0 0 180 160" fill="none" xmlns="http://www.w3.org/2000/svg" className="sc-illustration">
      {/* Books stack */}
      <rect x="30" y="108" width="110" height="18" rx="5" fill="#dcd8f8" opacity="0.9"/>
      <rect x="34" y="92" width="102" height="18" rx="5" fill="#e8e5fb" opacity="0.9"/>
      <rect x="38" y="78" width="94" height="16" rx="4" fill="#f0eeff" opacity="0.9"/>
      {/* Book pages lines */}
      <line x1="46" y1="84" x2="124" y2="84" stroke="#d0cbf5" strokeWidth="1.2" opacity="0.6"/>
      <line x1="46" y1="88" x2="110" y2="88" stroke="#d0cbf5" strokeWidth="1.2" opacity="0.6"/>
      {/* Graduation cap board */}
      <rect x="42" y="52" width="90" height="12" rx="3" fill="#9b8fe8" opacity="0.85" transform="rotate(-2 42 52)"/>
      {/* Cap top */}
      <polygon points="85,28 140,52 85,68 30,52" fill="#a99dff" opacity="0.9"/>
      <polygon points="85,28 140,52 85,40" fill="#8b7ee0" opacity="0.7"/>
      {/* Cap button */}
      <circle cx="85" cy="28" r="5" fill="#c4baff"/>
      {/* Tassel string */}
      <line x1="140" y1="52" x2="145" y2="75" stroke="#e8c874" strokeWidth="2.5" strokeLinecap="round"/>
