// ── Main component ─────────────────────────────────────────────────────────
export default function PracticePage({ navigate, user, onLogout }) {
  const [scenario, setScenario] = useState(null);
  const [loading, setLoading]   = useState(false);
  const [loadingMsg, setLoadingMsg] = useState("");

  const {
    isRecording, audioBlob, duration, elapsed, error,
    startRecording, stopRecording, getExtension,
  } = useRecorder();

  const fmt = (s) =>
    `${Math.floor(s / 60).toString().padStart(2, "0")}:${(s % 60).toString().padStart(2, "0")}`;

  const handleAnalyze = async () => {
    if (!audioBlob || !scenario) return;
    setLoading(true);
    const messages = [
      "Uploading your recording…",
      "Transcribing with Whisper…",
      "Analyzing speech patterns…",
      "Generating AI coaching…",
    ];
    let msgIdx = 0;
    setLoadingMsg(messages[0]);
    const msgInterval = setInterval(() => {
      msgIdx = (msgIdx + 1) % messages.length;
      setLoadingMsg(messages[msgIdx]);
    }, 2200);

    try {
      const formData = new FormData();
      const ext = getExtension ? getExtension() : "webm";
      formData.append("audio", audioBlob, `recording.${ext}`);
      formData.append("scenario", scenario.label);
      formData.append("duration", duration.toString());

      const res  = await fetch(`${API_URL}/api/analyze`, { method: "POST", body: formData });
      let data;
      try { data = await res.json(); } catch {
        throw new Error(`Server returned invalid response (status ${res.status})`);
      }
      if (!res.ok) throw new Error(data?.error || `Server error ${res.status}`);
      if (!data || (!data.transcript && !data.metrics)) throw new Error("Analysis returned empty results. Please try again.");

      clearInterval(msgInterval);
      navigate("results", data);
    } catch (err) {
      clearInterval(msgInterval);
      setLoading(false);
      alert("Error: " + err.message);
    }
  };

  // ── LOADING ────────────────────────────────────────────────────────────
  if (loading) {
    return (
      <div className="pp-root">
        <Sidebar navigate={navigate} onLogout={onLogout} user={user} />
        <div className="pp-main">
          <Topbar user={user} />
          <div className="pp-content pp-center">
            <div className="pp-loading-box">
              <div className="pp-spinner" />
              <p className="pp-loading-msg">{loadingMsg}</p>
              <p className="pp-loading-sub">Hang tight — this takes about 10–20 seconds</p>
            </div>
          </div>
        </div>
      </div>
    );
  }

  // ── SCENARIO SELECTION ────────────────────────────────────────────────
  if (!scenario) {
    return (
      <div className="pp-root">
        <Sidebar navigate={navigate} onLogout={onLogout} user={user} />
        <div className="pp-main">
          <Topbar user={user} />
          <div className="pp-content">
            {/* Back + step badge */}
            <div className="pp-top-row">
              <button className="pp-back-btn" onClick={() => navigate("dashboard")}>
                <svg width="16" height="16" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth="2">
                  <path strokeLinecap="round" strokeLinejoin="round" d="M15 19l-7-7 7-7"/>
                </svg>
                Back
              </button>
              <span className="pp-step-badge">STEP 1 OF 2</span>
              <div />
            </div>

            {/* Heading */}
            <div className="pp-heading">
              <h1>Choose a scenario</h1>
              <p>Pick the speaking situation you want to practice today.</p>
            </div>

            {/* Scenario grid */}
            <div className="pp-scenario-grid">
              {SCENARIOS.map((s) => (
                <button key={s.id} className="pp-sc-card" onClick={() => setScenario(s)}>
                  {/* Icon badge */}
                  <div className="pp-sc-icon-wrap">
                    <svg width="20" height="20" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth="2">
                      <path strokeLinecap="round" strokeLinejoin="round" d={s.iconPath}/>
                    </svg>
                  </div>

                  {/* Text */}
                  <div className="pp-sc-text">
                    <span className="pp-sc-label">{s.label}</span>
                    <span className="pp-sc-hint">{s.hint}</span>
                  </div>

                  {/* Chevron */}
                  <div className="pp-sc-chevron">
                    <svg width="18" height="18" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth="2.5">
                      <path strokeLinecap="round" strokeLinejoin="round" d="M9 5l7 7-7 7"/>
                    </svg>
                  </div>

                  {/* 3D illustration */}
                  <div className="pp-sc-art">
                    <s.Illustration />
                  </div>
                </button>
              ))}
            </div>
          </div>
        </div>
      </div>
    );
  }

  // ── RECORDING ─────────────────────────────────────────────────────────
  return (
    <div className="pp-root">
      <Sidebar navigate={navigate} onLogout={onLogout} user={user} />
      <div className="pp-main">
        <Topbar user={user} />
        <div className="pp-content">
          {/* Back + step badge */}
          <div className="pp-top-row">
            <button className="pp-back-btn" onClick={() => setScenario(null)}>
              <svg width="16" height="16" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth="2">
                <path strokeLinecap="round" strokeLinejoin="round" d="M15 19l-7-7 7-7"/>
              </svg>
              Back
            </button>
            <span className="pp-step-badge">STEP 2 OF 2</span>
            <div />
          </div>

          {/* Heading */}
          <div className="pp-heading">
            <h1>Record your speech</h1>
            <p>
              <span className="pp-scenario-chip">
                {scenario.label}
              </span>
            </p>
          </div>

          {/* Record card */}
          <div className="pp-record-card">
            <div className="pp-timer">{fmt(isRecording ? elapsed : duration)}</div>

            {isRecording && (
              <div className="pp-waveform">
                {[...Array(11)].map((_, i) => (
                  <div key={i} className="pp-wave-bar" style={{ "--d": `${i * 0.09}s` }} />
                ))}
              </div>
            )}

            <p className="pp-record-status">
              {!isRecording && !audioBlob && "Press the button below to start recording"}
              {isRecording && "Recording… speak clearly into your microphone"}
              {!isRecording && audioBlob && `✅ Recording ready · ${fmt(duration)}`}
            </p>

            {error && <p className="pp-record-error">⚠️ {error}</p>}

            <button
              className={`pp-record-btn ${isRecording ? "pp-recording" : ""}`}
              onClick={isRecording ? stopRecording : startRecording}
            >
              {isRecording ? (
                <svg width="28" height="28" viewBox="0 0 28 28" fill="white">
                  <rect x="6" y="6" width="16" height="16" rx="3"/>
                </svg>
              ) : (
                <svg width="28" height="28" viewBox="0 0 28 28" fill="white">
                  <rect x="10" y="4" width="8" height="14" rx="4"/>
                  <path d="M5 14a9 9 0 0018 0" stroke="white" strokeWidth="2" fill="none" strokeLinecap="round"/>
                  <line x1="14" y1="23" x2="14" y2="26" stroke="white" strokeWidth="2" strokeLinecap="round"/>
                </svg>
              )}
            </button>
            <p className="pp-record-hint">{isRecording ? "Tap to stop" : "Tap to record"}</p>

            {audioBlob && !isRecording && (
              <div className="pp-analyze-row">
                <button className="pp-btn-primary" onClick={handleAnalyze}>
                  ✨ Analyze My Speech
                </button>
                <button className="pp-btn-ghost" onClick={startRecording}>
                  🔄 Re-record
                </button>
              </div>
            )}
          </div>

          {/* Tips */}
          <div className="pp-tips">
            <div className="pp-tip">💡 Speak at a comfortable pace (120–160 WPM is ideal)</div>
            <div className="pp-tip">🎯 Avoid "uh", "um", "like" — pause instead</div>
            <div className="pp-tip">⏱️ Aim for at least 30 seconds for better analysis</div>
          </div>
        </div>
      </div>
    </div>
  );
}
